INSERT INTO ordena_frases (subject_id, level, grades, sentence) VALUES
('economia', 'bachillerato', '{1}', 'La curva de demanda tiene pendiente negativa porque al aumentar el precio la cantidad demandada disminuye'),
('economia', 'bachillerato', '{1}', 'La elasticidad precio de la demanda mide cómo varía la cantidad demandada ante un cambio porcentual en el precio'),
('economia', 'bachillerato', '{1}', 'Los bienes inferiores son aquellos cuya demanda disminuye cuando aumenta la renta disponible del consumidor'),
('economia', 'bachillerato', '{1}', 'El excedente del consumidor es la diferencia entre lo que está dispuesto a pagar y lo que realmente paga'),
('economia', 'bachillerato', '{1}', 'La curva de oferta tiene pendiente positiva porque los productores ofrecen más cantidad a precios más altos'),
('economia', 'bachillerato', '{1}', 'Un mercado de competencia perfecta se caracteriza por muchos oferentes y demandantes que aceptan el precio de equilibrio'),
('economia', 'bachillerato', '{1}', 'El oligopolio es una estructura de mercado donde unas pocas empresas controlan la mayor parte de la producción'),
('economia', 'bachillerato', '{1}', 'La competencia monopolística combina elementos de competencia perfecta con diferenciación de producto entre los vendedores'),
('economia', 'bachillerato', '{1}', 'Los bienes sustitutivos son aquellos que pueden reemplazarse mutuamente al satisfacer una necesidad similar del consumidor'),
('economia', 'bachillerato', '{1}', 'Los bienes complementarios se consumen conjuntamente y cuando sube el precio de uno disminuye la demanda del otro'),
('economia', 'bachillerato', '{1}', 'La utilidad marginal es la satisfacción adicional que obtiene un consumidor al consumir una unidad más de un bien'),
('economia', 'bachillerato', '{1}', 'La ley de rendimientos decrecientes establece que cada factor adicional aporta menos producción si los demás permanecen constantes'),
('economia', 'bachillerato', '{1}', 'El PIB nominal se calcula con los precios corrientes mientras que el PIB real utiliza los precios de un año base'),
('economia', 'bachillerato', '{1}', 'La tasa de desempleo se calcula dividiendo la población desempleada entre la población activa y multiplicando por cien'),
('economia', 'bachillerato', '{1}', 'El Índice de Precios al Consumo mide la variación media de los precios de una cesta representativa de bienes'),
('economia', 'bachillerato', '{1}', 'La deflación es una bajada generalizada y sostenida de los precios que puede frenar el consumo y la inversión'),
('economia', 'bachillerato', '{1}', 'La estanflación combina estancamiento económico con inflación elevada creando una situación especialmente difícil de gestionar'),
('economia', 'bachillerato', '{1}', 'El multiplicador keynesiano indica cuánto aumenta la renta nacional por cada unidad adicional de gasto público invertida'),
('economia', 'bachillerato', '{1}', 'Los estabilizadores automáticos como las prestaciones por desempleo suavizan los ciclos económicos sin necesidad de intervención deliberada'),
('economia', 'bachillerato', '{1}', 'El tipo de interés nominal no tiene en cuenta la inflación mientras que el real sí descuenta su efecto'),
('economia', 'bachillerato', '{1}', 'La Reserva Federal y el Banco Central Europeo son los principales bancos centrales del mundo occidental actual'),
('economia', 'bachillerato', '{1}', 'El encaje bancario es el porcentaje de depósitos que los bancos deben mantener como reservas obligatorias sin prestar'),
('economia', 'bachillerato', '{1}', 'El proceso de creación de dinero bancario se produce cuando los bancos prestan parte de los depósitos que reciben'),
('economia', 'bachillerato', '{1}', 'Las operaciones de mercado abierto consisten en la compra y venta de deuda pública por parte del banco central'),
('economia', 'bachillerato', '{1}', 'La deuda pública representa el total de obligaciones financieras acumuladas por el Estado con sus acreedores nacionales e internacionales'),
('economia', 'bachillerato', '{1}', 'El déficit público se produce cuando los gastos del Estado superan sus ingresos durante un ejercicio fiscal determinado'),
('economia', 'bachillerato', '{1}', 'La presión fiscal mide el porcentaje del PIB que los ciudadanos destinan al pago de impuestos y cotizaciones sociales'),
('economia', 'bachillerato', '{1}', 'Los impuestos indirectos como el IVA gravan el consumo de bienes y servicios independientemente de la renta del contribuyente'),
('economia', 'bachillerato', '{1}', 'La renta per cápita se obtiene dividiendo el PIB total de un país entre su número de habitantes'),
('economia', 'bachillerato', '{1}', 'El Índice de Desarrollo Humano combina indicadores de salud educación y renta para medir el bienestar de un país'),
('economia', 'bachillerato', '{1}', 'La balanza comercial registra la diferencia entre las exportaciones y las importaciones de bienes de un país'),
('economia', 'bachillerato', '{1}', 'Un arancel es un impuesto que se aplica a las mercancías importadas para proteger la producción nacional de la competencia'),
('economia', 'bachillerato', '{1}', 'El proteccionismo comercial utiliza aranceles y cuotas para limitar las importaciones y favorecer la industria nacional'),
('economia', 'bachillerato', '{1}', 'El librecambismo defiende la eliminación de barreras comerciales para que los países se beneficien del comercio internacional'),
('economia', 'bachillerato', '{1}', 'La ventaja absoluta se da cuando un país produce un bien usando menos recursos que cualquier otro país competidor'),
('economia', 'bachillerato', '{1}', 'La ventaja comparativa explica que un país debe especializarse en producir los bienes con menor coste de oportunidad relativo'),
('economia', 'bachillerato', '{1}', 'El tipo de cambio expresa cuántas unidades de una moneda se necesitan para adquirir una unidad de otra moneda'),
('economia', 'bachillerato', '{1}', 'Una depreciación de la moneda nacional abarata las exportaciones pero encarece las importaciones de productos extranjeros'),
('economia', 'bachillerato', '{1}', 'El Fondo Monetario Internacional supervisa el sistema monetario global y presta asistencia financiera a países en dificultades'),
('economia', 'bachillerato', '{1}', 'El Banco Mundial financia proyectos de desarrollo en países con economías emergentes para reducir la pobreza mundial'),
('economia', 'bachillerato', '{1}', 'La Organización Mundial del Comercio promueve la liberalización del comercio internacional y resuelve disputas entre países miembros'),
('economia', 'bachillerato', '{1}', 'Los ciclos económicos alternan fases de expansión y recesión en la actividad productiva de un país a lo largo del tiempo'),
('economia', 'bachillerato', '{1}', 'La fase de recesión económica se caracteriza por la caída del PIB el aumento del desempleo y la reducción del consumo'),
('economia', 'bachillerato', '{1}', 'La economía sumergida comprende actividades productivas legales que no se declaran para evitar el pago de impuestos'),
('economia', 'bachillerato', '{1}', 'El flujo circular de la renta muestra cómo el dinero circula entre hogares y empresas a través de los mercados'),
('economia', 'bachillerato', '{1}', 'La frontera de posibilidades de producción muestra las combinaciones máximas de bienes que puede producir una economía eficiente'),
('economia', 'bachillerato', '{1}', 'Los factores productivos clásicos son la tierra el trabajo el capital y la capacidad empresarial del emprendedor'),
('economia', 'bachillerato', '{1}', 'La escasez de recursos obliga a las sociedades a elegir qué producir cómo producir y para quién producir'),
('economia', 'bachillerato', '{1}', 'El sistema de economía de mercado asigna los recursos mediante la interacción libre de la oferta y la demanda'),
('economia', 'bachillerato', '{1}', 'La economía planificada centraliza las decisiones de producción y distribución en manos del Estado sin intervención del mercado'),
('economia', 'bachillerato', '{1}', 'La economía mixta combina elementos del libre mercado con la intervención del Estado para corregir sus fallos'),
('economia', 'bachillerato', '{1}', 'Los fallos de mercado incluyen las externalidades los bienes públicos la información asimétrica y el poder de monopolio'),
('economia', 'bachillerato', '{1}', 'Los bienes públicos puros se caracterizan por ser no rivales y no excluyentes en su consumo por los ciudadanos'),
('economia', 'bachillerato', '{1}', 'La información asimétrica se produce cuando una de las partes de una transacción posee más datos relevantes que la otra'),
('economia', 'bachillerato', '{1}', 'El coeficiente de Gini mide la desigualdad de ingresos en un país donde cero es igualdad perfecta y uno desigualdad total'),
('economia', 'bachillerato', '{1}', 'La curva de Lorenz representa gráficamente el grado de desigualdad en la distribución de la renta de una población'),
('economia', 'bachillerato', '{1}', 'Las políticas redistributivas transfieren renta de los sectores más ricos a los más desfavorecidos para reducir la desigualdad'),
('economia', 'bachillerato', '{1}', 'El salario mínimo interprofesional establece la retribución más baja que puede recibir un trabajador por su jornada laboral'),
('economia', 'bachillerato', '{1}', 'La negociación colectiva permite a sindicatos y empresarios acordar las condiciones laborales de un sector o empresa concretos'),
('economia', 'bachillerato', '{1}', 'El desempleo friccional afecta a trabajadores que están en proceso de transición entre un empleo y otro nuevo'),
('economia', 'bachillerato', '{1}', 'El desempleo cíclico aumenta durante las recesiones económicas y disminuye en las fases de crecimiento y expansión'),
('economia', 'bachillerato', '{1}', 'La población activa incluye a todas las personas en edad laboral que trabajan o buscan activamente un empleo'),
('economia', 'bachillerato', '{1}', 'La deslocalización empresarial traslada la producción a países con menores costes laborales para aumentar la competitividad'),
('economia', 'bachillerato', '{1}', 'Las multinacionales operan en varios países y sus decisiones de inversión influyen en las economías nacionales receptoras'),
('economia', 'bachillerato', '{1}', 'La integración económica europea ha pasado por etapas desde la zona de libre comercio hasta la unión monetaria'),
('economia', 'bachillerato', '{1}', 'El euro es la moneda común de la eurozona que elimina el riesgo cambiario entre los países que la adoptan'),
('economia', 'bachillerato', '{1}', 'Los Presupuestos Generales del Estado recogen las previsiones de ingresos y gastos del sector público para cada año'),
('economia', 'bachillerato', '{1}', 'La evasión fiscal es un delito que consiste en ocultar ingresos para no pagar los impuestos correspondientes al Estado'),
('economia', 'bachillerato', '{1}', 'Los subsidios son transferencias del Estado que reducen el coste de producción o el precio final para el consumidor'),
('economia', 'bachillerato', '{1}', 'La productividad del trabajo mide la cantidad de bienes y servicios que produce un trabajador por hora de trabajo'),
('economia', 'bachillerato', '{1}', 'El emprendimiento impulsa la innovación y la creación de empleo al convertir ideas en nuevos proyectos empresariales viables'),
('economia', 'bachillerato', '{1}', 'El crecimiento económico sostenible busca aumentar la producción sin agotar los recursos naturales para las generaciones futuras'),
('economia', 'bachillerato', '{1}', 'La huella ecológica mide la superficie de tierra productiva necesaria para satisfacer el consumo de una población determinada'),
('economia', 'bachillerato', '{1}', 'Los mercados financieros facilitan la compraventa de activos como acciones y bonos entre ahorradores e inversores de todo el mundo'),
('economia', 'bachillerato', '{1}', 'Las acciones representan una participación en la propiedad de una empresa y dan derecho a recibir dividendos por los beneficios'),
('economia', 'bachillerato', '{1}', 'Los bonos del Estado son títulos de deuda pública que pagan un interés fijo durante un período determinado de tiempo'),
('economia', 'bachillerato', '{1}', 'La prima de riesgo mide la diferencia de rentabilidad entre la deuda de un país y la del país de referencia'),
('economia', 'bachillerato', '{1}', 'El consumo responsable implica tomar decisiones de compra considerando el impacto social y medioambiental de los productos'),
('economia', 'bachillerato', '{1}', 'La economía circular busca reducir los residuos reutilizando y reciclando materiales para alargar su vida útil al máximo'),
('economia', 'bachillerato', '{1}', 'Los paraísos fiscales ofrecen ventajas tributarias a empresas y particulares que quieren reducir su carga impositiva de forma legal'),
('economia', 'bachillerato', '{1}', 'La demanda agregada es la suma del consumo la inversión el gasto público y las exportaciones netas de una economía'),
('economia', 'bachillerato', '{1}', 'La oferta agregada representa la producción total de bienes y servicios que las empresas están dispuestas a ofrecer'),
('economia', 'bachillerato', '{1}', 'La política fiscal expansiva aumenta el gasto público o reduce los impuestos para estimular la actividad económica nacional'),
('economia', 'bachillerato', '{1}', 'La política monetaria restrictiva eleva los tipos de interés para reducir la cantidad de dinero en circulación y frenar la inflación'),
('economia', 'bachillerato', '{1}', 'El mercado de trabajo se rige por la oferta de los trabajadores y la demanda de las empresas que los contratan');
INSERT INTO ordena_frases (subject_id, level, grades, sentence) VALUES
('economia-empresa', 'bachillerato', '{2}', 'La sociedad limitada requiere un capital social mínimo de tres mil euros y tiene responsabilidad limitada al capital aportado'),
('economia-empresa', 'bachillerato', '{2}', 'El empresario individual es una persona física que ejerce una actividad empresarial respondiendo con todo su patrimonio personal'),
('economia-empresa', 'bachillerato', '{2}', 'La sociedad cooperativa se basa en la participación democrática de los socios que aportan trabajo y capital a partes iguales'),
('economia-empresa', 'bachillerato', '{2}', 'Las franquicias permiten utilizar la marca y el modelo de negocio de otra empresa a cambio del pago de una licencia'),
('economia-empresa', 'bachillerato', '{2}', 'La sociedad comanditaria tiene dos tipos de socios los colectivos con responsabilidad ilimitada y los comanditarios con responsabilidad limitada'),
('economia-empresa', 'bachillerato', '{2}', 'El Registro Mercantil es la institución donde deben inscribirse las sociedades para adquirir personalidad jurídica y publicidad legal'),
('economia-empresa', 'bachillerato', '{2}', 'El activo del balance recoge los bienes y derechos de la empresa ordenados de menor a mayor grado de liquidez'),
('economia-empresa', 'bachillerato', '{2}', 'El pasivo del balance representa las obligaciones y deudas que la empresa tiene con terceros ajenos a la propiedad'),
('economia-empresa', 'bachillerato', '{2}', 'El patrimonio neto es la diferencia entre el activo total y el pasivo total de la empresa en un momento dado'),
('economia-empresa', 'bachillerato', '{2}', 'La cuenta de pérdidas y ganancias refleja los ingresos y gastos del ejercicio para determinar el resultado económico final'),
('economia-empresa', 'bachillerato', '{2}', 'La amortización contable refleja la pérdida de valor de los activos fijos por el uso o el paso del tiempo'),
('economia-empresa', 'bachillerato', '{2}', 'El ratio de liquidez compara el activo corriente con el pasivo corriente para evaluar la capacidad de pago a corto plazo'),
('economia-empresa', 'bachillerato', '{2}', 'El ratio de endeudamiento mide la proporción de deuda sobre los recursos propios para evaluar el riesgo financiero'),
('economia-empresa', 'bachillerato', '{2}', 'La rentabilidad económica relaciona el beneficio antes de intereses e impuestos con el activo total invertido en la empresa'),
('economia-empresa', 'bachillerato', '{2}', 'La rentabilidad financiera mide el beneficio neto obtenido en relación con los recursos propios aportados por los accionistas'),
('economia-empresa', 'bachillerato', '{2}', 'El apalancamiento financiero indica si la empresa se beneficia de endeudarse cuando la rentabilidad supera al coste de la deuda'),
('economia-empresa', 'bachillerato', '{2}', 'El fondo de maniobra positivo garantiza que la empresa puede atender sus obligaciones de pago a corto plazo con solvencia'),
('economia-empresa', 'bachillerato', '{2}', 'La Tasa Interna de Retorno es el tipo de descuento que iguala el valor actual neto de una inversión a cero'),
('economia-empresa', 'bachillerato', '{2}', 'El plazo de recuperación o payback indica el tiempo necesario para recuperar la inversión inicial de un proyecto empresarial'),
('economia-empresa', 'bachillerato', '{2}', 'Las fuentes de financiación ajena incluyen préstamos bancarios emisión de obligaciones y crédito comercial de los proveedores'),
('economia-empresa', 'bachillerato', '{2}', 'El leasing es un contrato de arrendamiento financiero que permite usar un bien a cambio de cuotas con opción de compra'),
('economia-empresa', 'bachillerato', '{2}', 'El factoring permite a una empresa cobrar anticipadamente sus facturas cediendo los derechos de cobro a una entidad financiera'),
('economia-empresa', 'bachillerato', '{2}', 'El ciclo de explotación comprende desde la compra de materias primas hasta el cobro de las ventas del producto terminado'),
('economia-empresa', 'bachillerato', '{2}', 'El período medio de maduración mide el tiempo que tarda la empresa en recuperar cada euro invertido en su actividad'),
('economia-empresa', 'bachillerato', '{2}', 'La gestión de inventarios busca mantener el nivel óptimo de existencias minimizando costes de almacenamiento y de ruptura de stock'),
('economia-empresa', 'bachillerato', '{2}', 'El método Just in Time reduce los inventarios produciendo solo lo necesario en el momento preciso según la demanda real'),
('economia-empresa', 'bachillerato', '{2}', 'La cadena de valor descompone las actividades de la empresa para identificar las fuentes de ventaja competitiva en cada fase'),
('economia-empresa', 'bachillerato', '{2}', 'Las economías de escala reducen el coste unitario de producción al aumentar el volumen total de unidades fabricadas'),
('economia-empresa', 'bachillerato', '{2}', 'La investigación de mercados recopila y analiza información sobre consumidores y competidores para tomar decisiones comerciales fundamentadas'),
('economia-empresa', 'bachillerato', '{2}', 'El ciclo de vida de un producto pasa por las fases de introducción crecimiento madurez y declive en el mercado'),
('economia-empresa', 'bachillerato', '{2}', 'La marca es un signo distintivo que identifica los productos de una empresa y los diferencia de los de la competencia'),
('economia-empresa', 'bachillerato', '{2}', 'La política de precios puede basarse en los costes de producción en la competencia o en el valor percibido por el cliente'),
('economia-empresa', 'bachillerato', '{2}', 'El canal de distribución es el camino que recorre un producto desde el fabricante hasta el consumidor final del mercado'),
('economia-empresa', 'bachillerato', '{2}', 'El comercio electrónico permite a las empresas vender productos y servicios directamente al consumidor a través de plataformas digitales'),
('economia-empresa', 'bachillerato', '{2}', 'La publicidad busca informar y persuadir al público objetivo para generar conocimiento y preferencia hacia un producto o servicio'),
('economia-empresa', 'bachillerato', '{2}', 'La promoción de ventas utiliza técnicas como descuentos y regalos para estimular la compra inmediata de un producto específico'),
('economia-empresa', 'bachillerato', '{2}', 'Las relaciones públicas gestionan la imagen corporativa de la empresa ante los distintos grupos de interés y la opinión pública'),
('economia-empresa', 'bachillerato', '{2}', 'La fidelización del cliente busca mantener relaciones duraderas y rentables mediante la satisfacción continua de sus necesidades y expectativas'),
('economia-empresa', 'bachillerato', '{2}', 'El organigrama es la representación gráfica de la estructura organizativa que muestra los departamentos y sus relaciones jerárquicas'),
('economia-empresa', 'bachillerato', '{2}', 'La departamentalización puede organizarse por funciones por productos por zonas geográficas o por tipos de clientes atendidos'),
('economia-empresa', 'bachillerato', '{2}', 'La centralización concentra la toma de decisiones en la alta dirección mientras la descentralización las delega en niveles inferiores'),
('economia-empresa', 'bachillerato', '{2}', 'La dirección estratégica define los objetivos a largo plazo y las acciones necesarias para conseguir una ventaja competitiva sostenible'),
('economia-empresa', 'bachillerato', '{2}', 'La estrategia de diferenciación busca ofrecer un producto único y superior por el que los clientes paguen un precio premium'),
('economia-empresa', 'bachillerato', '{2}', 'La estrategia de liderazgo en costes persigue producir a menor coste que la competencia manteniendo una calidad aceptable'),
('economia-empresa', 'bachillerato', '{2}', 'La motivación laboral influye directamente en el rendimiento de los empleados y en la consecución de los objetivos empresariales'),
('economia-empresa', 'bachillerato', '{2}', 'La teoría de Maslow organiza las necesidades humanas en cinco niveles desde las fisiológicas hasta la autorrealización personal'),
('economia-empresa', 'bachillerato', '{2}', 'La teoría de Herzberg distingue entre factores higiénicos que evitan la insatisfacción y factores motivadores que generan satisfacción'),
('economia-empresa', 'bachillerato', '{2}', 'El contrato de trabajo es un acuerdo entre empresario y trabajador que establece las condiciones de prestación de servicios laborales'),
('economia-empresa', 'bachillerato', '{2}', 'La nómina es el documento que detalla el salario bruto las deducciones y el salario neto que percibe el trabajador'),
('economia-empresa', 'bachillerato', '{2}', 'La formación continua del personal mejora las competencias de los empleados y aumenta la competitividad global de la empresa'),
('economia-empresa', 'bachillerato', '{2}', 'La evaluación del desempeño mide el rendimiento de los trabajadores comparándolo con los estándares establecidos por la organización'),
('economia-empresa', 'bachillerato', '{2}', 'El plan de empresa debe incluir un estudio de mercado un plan de operaciones y un plan económico financiero'),
('economia-empresa', 'bachillerato', '{2}', 'La viabilidad económica de un proyecto se demuestra cuando los ingresos previstos superan los costes totales a medio plazo'),
('economia-empresa', 'bachillerato', '{2}', 'El análisis del entorno general se realiza mediante el modelo PEST que estudia factores políticos económicos sociales y tecnológicos'),
('economia-empresa', 'bachillerato', '{2}', 'Las cinco fuerzas de Porter analizan la rivalidad entre competidores el poder de clientes proveedores y las amenazas de sustitutos'),
('economia-empresa', 'bachillerato', '{2}', 'La externalización o outsourcing consiste en contratar a empresas externas para realizar actividades que no son el núcleo del negocio'),
('economia-empresa', 'bachillerato', '{2}', 'La innovación tecnológica permite a las empresas mejorar sus procesos productivos y lanzar nuevos productos al mercado con ventaja'),
('economia-empresa', 'bachillerato', '{2}', 'La calidad total es una filosofía de gestión que busca la mejora continua en todos los procesos de la organización'),
('economia-empresa', 'bachillerato', '{2}', 'El diagrama de Gantt representa gráficamente la planificación temporal de las tareas y actividades de un proyecto empresarial'),
('economia-empresa', 'bachillerato', '{2}', 'La matriz BCG clasifica los productos de una empresa según su cuota de mercado y la tasa de crecimiento del sector'),
('economia-empresa', 'bachillerato', '{2}', 'La estrategia de diversificación consiste en que la empresa entre en nuevos mercados con nuevos productos para reducir riesgos'),
('economia-empresa', 'bachillerato', '{2}', 'La integración vertical supone que una empresa asume actividades que antes realizaban sus proveedores o sus distribuidores en la cadena'),
('economia-empresa', 'bachillerato', '{2}', 'La fusión empresarial se produce cuando dos o más sociedades se unen para crear una nueva entidad con mayor capacidad'),
('economia-empresa', 'bachillerato', '{2}', 'La absorción ocurre cuando una empresa adquiere otra que desaparece jurídicamente integrándose completamente en la empresa absorbente'),
('economia-empresa', 'bachillerato', '{2}', 'Las PYMES representan más del noventa por ciento del tejido empresarial español y generan la mayor parte del empleo'),
('economia-empresa', 'bachillerato', '{2}', 'El emprendimiento social crea empresas cuyo objetivo principal es resolver problemas sociales o medioambientales de forma sostenible'),
('economia-empresa', 'bachillerato', '{2}', 'El crowdfunding permite a los emprendedores obtener financiación de múltiples inversores pequeños a través de plataformas digitales especializadas'),
('economia-empresa', 'bachillerato', '{2}', 'Los stakeholders son todos los grupos de interés que se ven afectados por las decisiones y la actividad de la empresa'),
('economia-empresa', 'bachillerato', '{2}', 'La ética empresarial establece normas de conducta que guían el comportamiento honesto y responsable de la organización en sociedad'),
('economia-empresa', 'bachillerato', '{2}', 'El gobierno corporativo establece las reglas y procedimientos para la toma de decisiones en los órganos de dirección empresarial'),
('economia-empresa', 'bachillerato', '{2}', 'El balance social recoge información sobre las actuaciones de responsabilidad social que la empresa realiza con su entorno'),
('economia-empresa', 'bachillerato', '{2}', 'La gestión medioambiental integra la protección del medio ambiente en la estrategia empresarial para minimizar el impacto ecológico'),
('economia-empresa', 'bachillerato', '{2}', 'El coste marginal es el incremento en el coste total que supone producir una unidad adicional de un bien'),
('economia-empresa', 'bachillerato', '{2}', 'El umbral de rentabilidad se alcanza cuando los ingresos totales igualan a los costes totales de la empresa'),
('economia-empresa', 'bachillerato', '{2}', 'Las provisiones contables anticipan posibles pérdidas futuras y se registran como gasto para reflejar la imagen fiel del patrimonio'),
('economia-empresa', 'bachillerato', '{2}', 'El cash flow o flujo de caja mide la capacidad de la empresa para generar tesorería con sus operaciones habituales'),
('economia-empresa', 'bachillerato', '{2}', 'La auditoría externa verifica que las cuentas anuales de una empresa reflejan fielmente su situación económica y financiera'),
('economia-empresa', 'bachillerato', '{2}', 'La planificación empresarial establece los objetivos y las estrategias necesarias para alcanzarlos en un horizonte temporal definido'),
('economia-empresa', 'bachillerato', '{2}', 'El cuadro de mando integral evalúa el rendimiento de la empresa desde perspectivas financiera comercial interna y de aprendizaje'),
('economia-empresa', 'bachillerato', '{2}', 'La función de aprovisionamiento gestiona la compra almacenamiento y suministro de materiales necesarios para la actividad productiva'),
('economia-empresa', 'bachillerato', '{2}', 'El control de calidad verifica que los productos y servicios cumplen los estándares establecidos antes de llegar al consumidor'),
('economia-empresa', 'bachillerato', '{2}', 'La certificación ISO garantiza que los procesos de la empresa cumplen con las normas internacionales de gestión de calidad'),
('economia-empresa', 'bachillerato', '{2}', 'El benchmarking compara los procesos y resultados de la empresa con los de las mejores organizaciones del sector para mejorar'),
('economia-empresa', 'bachillerato', '{2}', 'La transformación digital permite a las empresas optimizar sus procesos y crear nuevos modelos de negocio mediante la tecnología'),
('economia-empresa', 'bachillerato', '{2}', 'Los costes directos se asignan fácilmente a un producto concreto mientras que los indirectos se reparten entre varios productos');
INSERT INTO ordena_frases (subject_id, level, grades, sentence) VALUES
('geografia', 'bachillerato', '{2}', 'Los Pirineos constituyen una barrera natural de más de cuatrocientos kilómetros entre la Península Ibérica y el resto de Europa'),
('geografia', 'bachillerato', '{2}', 'La Cordillera Cantábrica se extiende por el norte peninsular desde Galicia hasta el País Vasco delimitando la España húmeda'),
('geografia', 'bachillerato', '{2}', 'El Sistema Central divide la Meseta en dos mitades y tiene sus cumbres más altas en la Sierra de Gredos'),
('geografia', 'bachillerato', '{2}', 'La depresión del Guadalquivir es una llanura de materiales sedimentarios que se abre al Atlántico en forma de triángulo'),
('geografia', 'bachillerato', '{2}', 'La depresión del Ebro está encajada entre los Pirineos el Sistema Ibérico y la Cordillera Costero Catalana'),
('geografia', 'bachillerato', '{2}', 'Las Islas Baleares son un archipiélago de origen alpino que representa la prolongación del Sistema Bético bajo el Mediterráneo'),
('geografia', 'bachillerato', '{2}', 'El relieve volcánico de las Islas Canarias se originó por la actividad de un punto caliente en la placa africana'),
('geografia', 'bachillerato', '{2}', 'El Teide es el pico más alto de España con más de tres mil setecientos metros de altitud sobre el nivel del mar'),
('geografia', 'bachillerato', '{2}', 'Las rías gallegas son valles fluviales inundados por el mar que forman entrantes profundos en la costa atlántica'),
('geografia', 'bachillerato', '{2}', 'El modelado kárstico se forma por la disolución de rocas calizas y genera paisajes con dolinas simas y cuevas'),
('geografia', 'bachillerato', '{2}', 'El glaciarismo cuaternario dejó circos y valles en forma de U en las principales cordilleras de la Península Ibérica'),
('geografia', 'bachillerato', '{2}', 'El clima oceánico predomina en la cornisa cantábrica con precipitaciones abundantes y temperaturas suaves durante todo el año'),
('geografia', 'bachillerato', '{2}', 'El clima mediterráneo continentalizado del interior peninsular tiene veranos muy calurosos e inviernos fríos con gran amplitud térmica'),
('geografia', 'bachillerato', '{2}', 'La gota fría o DANA provoca lluvias torrenciales en el litoral mediterráneo especialmente durante los meses de otoño'),
('geografia', 'bachillerato', '{2}', 'La aridez del sureste peninsular se debe a la posición a sotavento de las cordilleras que bloquean las masas húmedas'),
('geografia', 'bachillerato', '{2}', 'Los ríos mediterráneos tienen un régimen irregular con fuertes crecidas otoñales y estiajes acusados durante el verano seco'),
('geografia', 'bachillerato', '{2}', 'La cuenca hidrográfica del Duero es la más extensa de la Península Ibérica y drena gran parte de la Submeseta Norte'),
('geografia', 'bachillerato', '{2}', 'Los acuíferos subterráneos son una reserva hídrica fundamental en las zonas semiáridas del levante y sureste español'),
('geografia', 'bachillerato', '{2}', 'Los trasvases como el Tajo Segura intentan equilibrar el desigual reparto de recursos hídricos entre cuencas excedentarias y deficitarias'),
('geografia', 'bachillerato', '{2}', 'La vegetación de la España atlántica se compone de bosques caducifolios de hayas robles y castaños en zonas húmedas'),
('geografia', 'bachillerato', '{2}', 'El bosque mediterráneo de encinas y alcornoques se adapta a la sequía estival con hojas pequeñas y raíces profundas'),
('geografia', 'bachillerato', '{2}', 'La dehesa es un ecosistema agrosilvopastoral típicamente ibérico que combina el arbolado disperso con los pastos y la ganadería'),
('geografia', 'bachillerato', '{2}', 'El matorral mediterráneo incluye formaciones como la maquia el matorral y la garriga según el grado de degradación del bosque'),
('geografia', 'bachillerato', '{2}', 'La transición demográfica española se completó en el siglo veinte pasando de altas tasas de natalidad y mortalidad a bajas'),
('geografia', 'bachillerato', '{2}', 'La pirámide de población española actual tiene forma de urna con base estrecha que refleja la baja natalidad persistente'),
('geografia', 'bachillerato', '{2}', 'La España vaciada describe las zonas rurales del interior que sufren una pérdida continua de población y servicios básicos'),
('geografia', 'bachillerato', '{2}', 'Las áreas metropolitanas concentran la mayor parte de la población española generando problemas de congestión y presión urbanística'),
('geografia', 'bachillerato', '{2}', 'El crecimiento natural de la población resulta de restar la tasa de mortalidad a la tasa de natalidad de un territorio'),
('geografia', 'bachillerato', '{2}', 'El saldo migratorio positivo de España a principios del siglo veintiuno transformó la composición demográfica del país notablemente'),
('geografia', 'bachillerato', '{2}', 'La tasa de fecundidad española es una de las más bajas de Europa con menos de dos hijos por mujer'),
('geografia', 'bachillerato', '{2}', 'La red urbana española tiene un modelo macrocéfalo con Madrid como centro y ciudades secundarias en la periferia litoral'),
('geografia', 'bachillerato', '{2}', 'El plano urbano irregular del casco histórico medieval contrasta con el plano ortogonal de los ensanches del siglo diecinueve'),
('geografia', 'bachillerato', '{2}', 'Los ensanches urbanos como el de Barcelona se diseñaron con calles en cuadrícula para ordenar el crecimiento de las ciudades'),
('geografia', 'bachillerato', '{2}', 'Las ciudades dormitorio de la periferia metropolitana albergan población que trabaja en el centro urbano y se desplaza diariamente'),
('geografia', 'bachillerato', '{2}', 'La gentrificación transforma barrios populares en zonas de mayor nivel económico desplazando a los residentes originales de menores recursos'),
('geografia', 'bachillerato', '{2}', 'La agricultura de regadío predomina en el litoral mediterráneo y produce frutas hortalizas y productos de huerta para la exportación'),
('geografia', 'bachillerato', '{2}', 'La agricultura de secano se extiende por la Meseta Central y cultiva cereales vid y olivo adaptados a la escasez de agua'),
('geografia', 'bachillerato', '{2}', 'España es el primer productor mundial de aceite de oliva concentrando la mayor parte de la producción en Andalucía'),
('geografia', 'bachillerato', '{2}', 'La ganadería intensiva de porcino y avícola se concentra en Cataluña Aragón y Castilla y León por la disponibilidad de piensos'),
('geografia', 'bachillerato', '{2}', 'La pesca española ha disminuido por el agotamiento de caladeros y las restricciones de la política pesquera comunitaria europea'),
('geografia', 'bachillerato', '{2}', 'El triángulo industrial del norte formado por País Vasco Cataluña y Madrid concentró históricamente la actividad fabril española'),
('geografia', 'bachillerato', '{2}', 'Los polígonos industriales de la periferia urbana agrupan fábricas y almacenes aprovechando suelo barato y buenas comunicaciones por carretera'),
('geografia', 'bachillerato', '{2}', 'Los parques tecnológicos impulsan la innovación reuniendo empresas de alta tecnología centros de investigación y universidades en un mismo espacio'),
('geografia', 'bachillerato', '{2}', 'El turismo de sol y playa sigue siendo el modelo predominante en el litoral mediterráneo y las islas españolas'),
('geografia', 'bachillerato', '{2}', 'El turismo rural ha crecido como alternativa sostenible que revitaliza las comarcas del interior y diversifica la economía local'),
('geografia', 'bachillerato', '{2}', 'La red de carreteras radial española tiene su centro en Madrid y conecta la capital con todas las capitales de provincia'),
('geografia', 'bachillerato', '{2}', 'El AVE ha reducido el tiempo de viaje entre las grandes ciudades españolas y ha potenciado la vertebración territorial'),
('geografia', 'bachillerato', '{2}', 'La Unión Europea ha financiado infraestructuras españolas a través de los fondos de cohesión y los fondos estructurales'),
('geografia', 'bachillerato', '{2}', 'El Mercado Único Europeo permite la libre circulación de mercancías servicios capitales y personas entre los estados miembros'),
('geografia', 'bachillerato', '{2}', 'Las comunidades autónomas ejercen competencias en educación sanidad y ordenación del territorio según el Estado de las autonomías'),
('geografia', 'bachillerato', '{2}', 'Los desequilibrios territoriales en España se manifiestan en las diferencias de renta empleo y servicios entre comunidades autónomas'),
('geografia', 'bachillerato', '{2}', 'La contaminación atmosférica de las grandes ciudades españolas se agrava por el tráfico rodado y las emisiones industriales'),
('geografia', 'bachillerato', '{2}', 'Los parques nacionales protegen los ecosistemas más representativos de España como Doñana Picos de Europa y las Cañadas del Teide'),
('geografia', 'bachillerato', '{2}', 'La erosión del suelo afecta a gran parte del territorio peninsular agravada por la deforestación y las prácticas agrícolas intensivas'),
('geografia', 'bachillerato', '{2}', 'La red Natura 2000 protege los hábitats y especies más valiosos de Europa e incluye numerosos espacios del territorio español'),
('geografia', 'bachillerato', '{2}', 'El cambio climático amenaza con aumentar la aridez y reducir los recursos hídricos disponibles en la mayor parte de España'),
('geografia', 'bachillerato', '{2}', 'La posición geográfica de España como puente entre Europa y África le otorga un papel estratégico en las relaciones internacionales'),
('geografia', 'bachillerato', '{2}', 'Las costas cantábricas son altas y rectilíneas con acantilados mientras que las mediterráneas alternan playas con pequeñas calas rocosas'),
('geografia', 'bachillerato', '{2}', 'El litoral atlántico andaluz presenta extensas playas de arena fina formadas por los aportes sedimentarios del río Guadalquivir'),
('geografia', 'bachillerato', '{2}', 'Los suelos arcillosos de las campiñas béticas son muy fértiles y sustentan cultivos de cereales girasol y olivar'),
('geografia', 'bachillerato', '{2}', 'La ganadería extensiva de ovino y caprino predomina en las zonas de montaña y las dehesas del oeste peninsular'),
('geografia', 'bachillerato', '{2}', 'La suburbanización ha provocado la expansión de las ciudades hacia municipios vecinos creando áreas periurbanas de urbanización difusa'),
('geografia', 'bachillerato', '{2}', 'La industria agroalimentaria es uno de los sectores manufactureros más importantes de España por volumen de producción y empleo'),
('geografia', 'bachillerato', '{2}', 'La minería española ha perdido importancia económica aunque mantiene la extracción de minerales no metálicos y rocas industriales'),
('geografia', 'bachillerato', '{2}', 'La dependencia energética de España se debe a la escasez de combustibles fósiles propios y la necesidad de importar petróleo'),
('geografia', 'bachillerato', '{2}', 'El Plan Hidrológico Nacional coordina la gestión del agua entre las distintas cuencas hidrográficas del territorio español'),
('geografia', 'bachillerato', '{2}', 'La vegetación de laurisilva en las Islas Canarias es un bosque subtropical relicto de gran valor ecológico y biogeográfico'),
('geografia', 'bachillerato', '{2}', 'Las marismas del Guadalquivir constituyen uno de los humedales más importantes de Europa y son hábitat de aves migratorias'),
('geografia', 'bachillerato', '{2}', 'El archipiélago canario presenta una gran diversidad de microclimas debido a la altitud la orientación y los vientos alisios'),
('geografia', 'bachillerato', '{2}', 'La presión turística sobre el litoral mediterráneo ha generado problemas de urbanización masiva y degradación de espacios naturales costeros'),
('geografia', 'bachillerato', '{2}', 'Las cuencas sedimentarias del interior peninsular acumularon materiales durante el Terciario formando llanuras arcillosas y páramos calizos'),
('geografia', 'bachillerato', '{2}', 'La silvicultura española se centra en la producción de madera corcho y resina especialmente en los bosques de pino y alcornoque'),
('geografia', 'bachillerato', '{2}', 'Los embalses regulan el caudal de los ríos abastecen de agua a las poblaciones y producen energía hidroeléctrica renovable'),
('geografia', 'bachillerato', '{2}', 'La inmigración extranjera ha contribuido al rejuvenecimiento demográfico aportando población joven en edad laboral y aumentando la natalidad'),
('geografia', 'bachillerato', '{2}', 'La tasa de urbanización española supera el ochenta por ciento indicando que la mayoría de la población vive en ciudades'),
('geografia', 'bachillerato', '{2}', 'El Camino de Santiago ha sido declarado Patrimonio de la Humanidad y es un recurso turístico cultural de primer orden'),
('geografia', 'bachillerato', '{2}', 'La política regional europea busca reducir las desigualdades económicas entre las regiones más desarrolladas y las menos favorecidas'),
('geografia', 'bachillerato', '{2}', 'El Estrecho de Gibraltar separa Europa de África por apenas catorce kilómetros y es una vía marítima de tráfico intenso'),
('geografia', 'bachillerato', '{2}', 'Las ciudades autónomas de Ceuta y Melilla se encuentran en el norte de África y tienen un estatuto jurídico especial'),
('geografia', 'bachillerato', '{2}', 'El Sistema Ibérico actúa como divisoria de aguas entre las cuencas del Duero Tajo Ebro Júcar y Turia'),
('geografia', 'bachillerato', '{2}', 'Los paisajes agrarios de España varían entre las parcelas minifundistas del norte y los latifundios del sur peninsular'),
('geografia', 'bachillerato', '{2}', 'El sector terciario avanzado incluye servicios financieros tecnológicos y de comunicaciones que impulsan la economía del conocimiento'),
('geografia', 'bachillerato', '{2}', 'La ordenación del territorio busca un desarrollo equilibrado y sostenible mediante la planificación de usos del suelo y recursos'),
('geografia', 'bachillerato', '{2}', 'La contaminación de los acuíferos por nitratos procedentes de la agricultura intensiva amenaza la calidad del agua subterránea'),
('geografia', 'bachillerato', '{2}', 'Las comarcas del interior peninsular sufren un proceso de despoblación que dificulta el mantenimiento de servicios públicos esenciales');
INSERT INTO ordena_frases (subject_id, level, grades, sentence) VALUES
('dibujo-tecnico', 'bachillerato', '{1}', 'La mediatriz de un segmento es la recta perpendicular que pasa por su punto medio dividiendo el segmento en dos partes iguales'),
('dibujo-tecnico', 'bachillerato', '{1}', 'La bisectriz de un ángulo es la semirrecta que divide al ángulo en dos partes iguales desde su vértice'),
('dibujo-tecnico', 'bachillerato', '{1}', 'El teorema de Tales permite dividir un segmento en partes iguales utilizando rectas paralelas y una recta secante'),
('dibujo-tecnico', 'bachillerato', '{1}', 'La sección áurea divide un segmento de modo que la proporción entre el todo y la parte mayor es el número áureo'),
('dibujo-tecnico', 'bachillerato', '{1}', 'Un polígono regular tiene todos sus lados y ángulos iguales y puede inscribirse en una circunferencia que pasa por sus vértices'),
('dibujo-tecnico', 'bachillerato', '{1}', 'El triángulo equilátero inscrito en una circunferencia se construye dividiendo la circunferencia en tres arcos iguales con el compás'),
('dibujo-tecnico', 'bachillerato', '{1}', 'El hexágono regular se construye fácilmente trasladando el radio de la circunferencia seis veces sobre su perímetro consecutivamente'),
('dibujo-tecnico', 'bachillerato', '{1}', 'El pentágono regular se construye a partir de la relación áurea y sus diagonales se cortan en proporción divina'),
('dibujo-tecnico', 'bachillerato', '{1}', 'La circunferencia es el lugar geométrico de los puntos del plano que equidistan de un punto central llamado centro'),
('dibujo-tecnico', 'bachillerato', '{1}', 'Las rectas tangentes a una circunferencia son perpendiculares al radio en el punto de contacto entre ambas'),
('dibujo-tecnico', 'bachillerato', '{1}', 'El enlace de dos rectas mediante un arco de circunferencia requiere encontrar los puntos de tangencia y el centro del arco'),
('dibujo-tecnico', 'bachillerato', '{1}', 'Las tangencias exteriores entre dos circunferencias se resuelven trazando la circunferencia auxiliar suma de los dos radios'),
('dibujo-tecnico', 'bachillerato', '{1}', 'Las tangencias interiores entre dos circunferencias se resuelven mediante la circunferencia auxiliar diferencia de los dos radios'),
('dibujo-tecnico', 'bachillerato', '{1}', 'La potencia de un punto respecto a una circunferencia es constante para cualquier recta secante trazada desde ese punto'),
('dibujo-tecnico', 'bachillerato', '{1}', 'El eje radical de dos circunferencias es el lugar geométrico de los puntos de igual potencia respecto a ambas'),
('dibujo-tecnico', 'bachillerato', '{1}', 'La inversión geométrica transforma circunferencias en rectas y viceversa manteniendo los ángulos de intersección entre las figuras'),
('dibujo-tecnico', 'bachillerato', '{1}', 'La homotecia es una transformación que amplía o reduce una figura manteniendo su forma desde un punto fijo llamado centro'),
('dibujo-tecnico', 'bachillerato', '{1}', 'La traslación desplaza todos los puntos de una figura la misma distancia y en la misma dirección sin deformarla'),
('dibujo-tecnico', 'bachillerato', '{1}', 'El giro o rotación transforma una figura haciéndola girar un ángulo determinado alrededor de un punto fijo del plano'),
('dibujo-tecnico', 'bachillerato', '{1}', 'La simetría axial refleja una figura respecto a una recta de modo que cada punto tiene su simétrico equidistante'),
('dibujo-tecnico', 'bachillerato', '{1}', 'La espiral de Arquímedes se construye con arcos de circunferencia de radio creciente y centros alternados sobre un diámetro'),
('dibujo-tecnico', 'bachillerato', '{1}', 'La óvalo se construye a partir de dos circunferencias de distinto radio enlazadas mediante arcos tangentes suaves'),
('dibujo-tecnico', 'bachillerato', '{1}', 'La parábola es una cónica cuya excentricidad es igual a uno y tiene un foco y una directriz equidistantes'),
('dibujo-tecnico', 'bachillerato', '{1}', 'La hipérbola tiene dos focos y se define como el lugar de los puntos cuya diferencia de distancias a los focos es constante'),
('dibujo-tecnico', 'bachillerato', '{1}', 'Las cónicas degeneradas se producen cuando el plano de corte pasa por el vértice del cono generando un punto o rectas'),
('dibujo-tecnico', 'bachillerato', '{1}', 'La excentricidad de una cónica determina su forma siendo menor que uno en la elipse igual a uno en la parábola'),
('dibujo-tecnico', 'bachillerato', '{1}', 'Las rectas directrices de una elipse son dos rectas perpendiculares al eje mayor situadas a ambos lados del centro'),
('dibujo-tecnico', 'bachillerato', '{1}', 'El sistema diédrico fue desarrollado por Gaspard Monge en el siglo dieciocho para representar objetos tridimensionales con precisión'),
('dibujo-tecnico', 'bachillerato', '{1}', 'La línea de tierra es la recta de intersección entre el plano horizontal y el plano vertical de proyección'),
('dibujo-tecnico', 'bachillerato', '{1}', 'La cota de un punto en el sistema diédrico es su distancia al plano horizontal de proyección medida en vertical'),
('dibujo-tecnico', 'bachillerato', '{1}', 'El alejamiento de un punto es su distancia al plano vertical de proyección medida en dirección perpendicular a él'),
('dibujo-tecnico', 'bachillerato', '{1}', 'Una recta horizontal tiene su proyección vertical paralela a la línea de tierra porque todos sus puntos tienen igual cota'),
('dibujo-tecnico', 'bachillerato', '{1}', 'Una recta frontal tiene su proyección horizontal paralela a la línea de tierra porque todos sus puntos tienen igual alejamiento'),
('dibujo-tecnico', 'bachillerato', '{1}', 'Una recta de perfil es perpendicular al plano de perfil y se proyecta como un punto en la vista lateral'),
('dibujo-tecnico', 'bachillerato', '{1}', 'Las trazas de una recta son los puntos donde la recta corta a los planos de proyección horizontal y vertical'),
('dibujo-tecnico', 'bachillerato', '{1}', 'Un plano oblicuo se define mediante tres puntos no alineados o bien por una recta y un punto exterior a ella'),
('dibujo-tecnico', 'bachillerato', '{1}', 'Las trazas de un plano son las rectas de intersección del plano con los planos horizontal y vertical de proyección'),
('dibujo-tecnico', 'bachillerato', '{1}', 'La verdadera magnitud de un segmento oblicuo se obtiene mediante un giro o un abatimiento sobre un plano de proyección'),
('dibujo-tecnico', 'bachillerato', '{1}', 'La perpendicularidad entre recta y plano en diédrico se comprueba verificando que la recta es perpendicular a dos del plano'),
('dibujo-tecnico', 'bachillerato', '{1}', 'La distancia entre dos rectas paralelas se obtiene hallando la recta perpendicular común y midiendo su verdadera magnitud'),
('dibujo-tecnico', 'bachillerato', '{1}', 'La intersección de dos planos es una recta que se determina hallando dos puntos comunes a ambos planos'),
('dibujo-tecnico', 'bachillerato', '{1}', 'La perspectiva caballera representa los objetos con el eje de profundidad inclinado a cuarenta y cinco grados y reducido a la mitad'),
('dibujo-tecnico', 'bachillerato', '{1}', 'La perspectiva isométrica utiliza tres ejes formando ángulos de ciento veinte grados entre sí con un coeficiente de reducción igual'),
('dibujo-tecnico', 'bachillerato', '{1}', 'La perspectiva militar mantiene la planta del objeto en verdadera magnitud y eleva las alturas sobre ella verticalmente'),
('dibujo-tecnico', 'bachillerato', '{1}', 'El sistema de planos acotados utiliza un solo plano de proyección horizontal e indica la cota de cada punto con un número'),
('dibujo-tecnico', 'bachillerato', '{1}', 'Los formatos normalizados de papel se basan en la serie A donde el A0 tiene una superficie de un metro cuadrado'),
('dibujo-tecnico', 'bachillerato', '{1}', 'Las líneas de cota se dibujan paralelas a la dimensión que acotan y terminan en flechas o trazos oblicuos'),
('dibujo-tecnico', 'bachillerato', '{1}', 'La línea de tipo continuo grueso se utiliza para representar las aristas y contornos visibles del objeto dibujado'),
('dibujo-tecnico', 'bachillerato', '{1}', 'La línea discontinua fina representa las aristas ocultas del objeto que no son visibles desde el punto de vista'),
('dibujo-tecnico', 'bachillerato', '{1}', 'La línea de trazos y puntos se emplea para dibujar ejes de simetría y centros de circunferencias en el plano'),
('dibujo-tecnico', 'bachillerato', '{1}', 'El cajetín o cuadro de rotulación se sitúa en la esquina inferior derecha del plano con datos del dibujo'),
('dibujo-tecnico', 'bachillerato', '{1}', 'La escala natural es uno a uno y se emplea cuando las dimensiones del objeto permiten dibujarlo a tamaño real'),
('dibujo-tecnico', 'bachillerato', '{1}', 'Las escalas de ampliación se usan para objetos muy pequeños representándolos a un tamaño mayor que el real'),
('dibujo-tecnico', 'bachillerato', '{1}', 'El método europeo de proyección sitúa el alzado en el centro la planta debajo y el perfil a la derecha del alzado'),
('dibujo-tecnico', 'bachillerato', '{1}', 'El concepto de lugar geométrico describe el conjunto de puntos que cumplen una o más condiciones geométricas determinadas'),
('dibujo-tecnico', 'bachillerato', '{1}', 'Los arcos carpanel se construyen con varios centros y se utilizan en arquitectura para cubrir vanos de gran anchura'),
('dibujo-tecnico', 'bachillerato', '{1}', 'La curva cicloide es la trayectoria que describe un punto de una circunferencia cuando esta rueda sobre una recta fija'),
('dibujo-tecnico', 'bachillerato', '{1}', 'La evolvente de una circunferencia es la curva trazada por el extremo de un hilo que se desenrolla de ella'),
('dibujo-tecnico', 'bachillerato', '{1}', 'El desarrollo de un cuerpo geométrico consiste en desplegar sus caras sobre un plano para construirlo en cartulina o metal'),
('dibujo-tecnico', 'bachillerato', '{1}', 'El trazado geométrico con regla y compás permite resolver problemas clásicos como la división de ángulos y segmentos'),
('dibujo-tecnico', 'bachillerato', '{1}', 'Los polígonos estrellados se construyen uniendo vértices no consecutivos de un polígono regular inscrito en una circunferencia'),
('dibujo-tecnico', 'bachillerato', '{1}', 'La construcción del decágono regular se basa en dividir la circunferencia en diez partes iguales usando la proporción áurea'),
('dibujo-tecnico', 'bachillerato', '{1}', 'Los centros de curvatura de una cónica varían a lo largo de la curva y determinan su radio de curvatura local'),
('dibujo-tecnico', 'bachillerato', '{1}', 'El trazado de rectas tangentes a cónicas desde un punto exterior requiere el uso de la polar del punto respecto a la cónica'),
('dibujo-tecnico', 'bachillerato', '{1}', 'La semejanza entre figuras geométricas mantiene la proporcionalidad de los lados y la igualdad de los ángulos correspondientes'),
('dibujo-tecnico', 'bachillerato', '{1}', 'Los ángulos inscritos en una semicircunferencia son siempre rectos según el teorema de Tales sobre la circunferencia'),
('dibujo-tecnico', 'bachillerato', '{1}', 'Las mediatrices de los lados de un triángulo se cortan en el circuncentro que es el centro de la circunferencia circunscrita'),
('dibujo-tecnico', 'bachillerato', '{1}', 'Las alturas de un triángulo se cortan en un punto llamado ortocentro que puede estar dentro o fuera del triángulo'),
('dibujo-tecnico', 'bachillerato', '{1}', 'El baricentro de un triángulo es el punto de intersección de las medianas y divide cada mediana en razón dos a uno'),
('dibujo-tecnico', 'bachillerato', '{1}', 'El incentro de un triángulo es el punto donde se cortan las bisectrices y es el centro de la circunferencia inscrita'),
('dibujo-tecnico', 'bachillerato', '{1}', 'La potencia de un punto permite determinar la relación entre segmentos de rectas secantes trazadas desde ese punto a una circunferencia'),
('dibujo-tecnico', 'bachillerato', '{1}', 'Las transformaciones geométricas conservan propiedades como la alineación de puntos y la tangencia entre curvas en las figuras resultantes'),
('dibujo-tecnico', 'bachillerato', '{1}', 'El arco capaz de un ángulo dado sobre un segmento es el arco de circunferencia desde el que se ve dicho segmento'),
('dibujo-tecnico', 'bachillerato', '{1}', 'Las curvas técnicas como las cónicas tienen aplicaciones directas en ingeniería arquitectura y diseño industrial contemporáneo'),
('dibujo-tecnico', 'bachillerato', '{1}', 'La proyección de un punto sobre un plano se obtiene trazando una perpendicular al plano que pase por dicho punto'),
('dibujo-tecnico', 'bachillerato', '{1}', 'Un prisma recto tiene sus aristas laterales perpendiculares a las bases y sus caras laterales son rectángulos paralelos'),
('dibujo-tecnico', 'bachillerato', '{1}', 'La pirámide recta tiene el vértice alineado perpendicularmente con el centro de la base y sus caras son triángulos isósceles'),
('dibujo-tecnico', 'bachillerato', '{1}', 'El cilindro de revolución se genera al girar un rectángulo alrededor de uno de sus lados como eje de simetría'),
('dibujo-tecnico', 'bachillerato', '{1}', 'El cono de revolución se genera haciendo girar un triángulo rectángulo alrededor de uno de sus catetos como eje'),
('dibujo-tecnico', 'bachillerato', '{1}', 'La esfera se genera al girar una semicircunferencia alrededor de su diámetro creando una superficie de revolución perfecta'),
('dibujo-tecnico', 'bachillerato', '{1}', 'El dodecaedro regular tiene doce caras pentagonales y es uno de los cinco poliedros platónicos junto con el icosaedro'),
('dibujo-tecnico', 'bachillerato', '{1}', 'Las rectas perpendiculares forman un ángulo de noventa grados entre sí y se verifican con la escuadra y el cartabón'),
('dibujo-tecnico', 'bachillerato', '{1}', 'La rotulación técnica normalizada utiliza letras y números con proporciones fijas para garantizar la legibilidad de los planos'),
('dibujo-tecnico', 'bachillerato', '{1}', 'Los instrumentos básicos del dibujo técnico incluyen el compás la regla la escuadra el cartabón y el transportador de ángulos'),
('dibujo-tecnico', 'bachillerato', '{1}', 'La cuadrícula isométrica facilita el trazado de perspectivas isométricas a mano alzada sin necesidad de regla y compás');
INSERT INTO ordena_frases (subject_id, level, grades, sentence) VALUES
('dibujo-tecnico', 'bachillerato', '{2}', 'El cambio de plano en diédrico permite obtener nuevas proyecciones que simplifican la resolución de problemas con elementos oblicuos'),
('dibujo-tecnico', 'bachillerato', '{2}', 'La sección de un prisma por un plano oblicuo produce un polígono cuya verdadera magnitud se obtiene por abatimiento'),
('dibujo-tecnico', 'bachillerato', '{2}', 'La sección de una esfera por cualquier plano es siempre una circunferencia cuyo radio depende de la posición del corte'),
('dibujo-tecnico', 'bachillerato', '{2}', 'La intersección de un cono con un plano paralelo a una generatriz produce una parábola como sección resultante'),
('dibujo-tecnico', 'bachillerato', '{2}', 'La sección de un cilindro recto por un plano oblicuo a su eje produce una elipse como curva de intersección'),
('dibujo-tecnico', 'bachillerato', '{2}', 'La intersección de dos superficies se resuelve hallando los puntos comunes mediante planos auxiliares secantes a ambas'),
('dibujo-tecnico', 'bachillerato', '{2}', 'El método de los planos auxiliares horizontales permite hallar la intersección de una superficie curva con otra geométrica'),
('dibujo-tecnico', 'bachillerato', '{2}', 'La sombra propia de un cuerpo es la zona de su superficie que no recibe la luz directa del foco luminoso'),
('dibujo-tecnico', 'bachillerato', '{2}', 'La sombra arrojada es la proyección de la sombra propia sobre los planos de proyección o sobre otros cuerpos cercanos'),
('dibujo-tecnico', 'bachillerato', '{2}', 'Las sombras en diédrico se determinan trazando rayos de luz que pasan por los vértices del objeto hasta los planos'),
('dibujo-tecnico', 'bachillerato', '{2}', 'La perspectiva cónica frontal tiene un solo punto de fuga situado en la línea de horizonte frente al observador'),
('dibujo-tecnico', 'bachillerato', '{2}', 'La perspectiva cónica oblicua utiliza dos puntos de fuga en la línea de horizonte para representar esquinas de edificios'),
('dibujo-tecnico', 'bachillerato', '{2}', 'El punto de vista del observador en perspectiva cónica determina la posición del punto principal y los puntos de distancia'),
('dibujo-tecnico', 'bachillerato', '{2}', 'La línea de horizonte en perspectiva cónica se sitúa a la altura de los ojos del observador sobre el plano geometral'),
('dibujo-tecnico', 'bachillerato', '{2}', 'El plano del cuadro es la superficie vertical transparente sobre la que se proyecta la escena en perspectiva cónica'),
('dibujo-tecnico', 'bachillerato', '{2}', 'Las rectas paralelas al plano geometral convergen en un punto de fuga situado en la línea de horizonte del observador'),
('dibujo-tecnico', 'bachillerato', '{2}', 'La perspectiva cónica de una circunferencia situada en un plano horizontal se representa como una elipse sobre el cuadro'),
('dibujo-tecnico', 'bachillerato', '{2}', 'Los puntos métricos permiten trasladar medidas reales al dibujo en perspectiva cónica manteniendo las proporciones del objeto'),
('dibujo-tecnico', 'bachillerato', '{2}', 'La perspectiva cónica de tres puntos de fuga se usa para representar edificios muy altos vistos desde abajo o desde arriba'),
('dibujo-tecnico', 'bachillerato', '{2}', 'El sistema de planos acotados se aplica en topografía para representar la superficie del terreno mediante curvas de nivel'),
('dibujo-tecnico', 'bachillerato', '{2}', 'Las curvas de nivel unen puntos de igual cota y su separación indica la pendiente del terreno representado'),
('dibujo-tecnico', 'bachillerato', '{2}', 'Un perfil topográfico se obtiene cortando el terreno con un plano vertical y dibujando la sección resultante a escala'),
('dibujo-tecnico', 'bachillerato', '{2}', 'La intersección de un plano con el terreno en planos acotados define la traza del camino o la plataforma'),
('dibujo-tecnico', 'bachillerato', '{2}', 'El sistema axonométrico ortogonal proyecta el objeto sobre el plano del cuadro con rayos perpendiculares a dicho plano'),
('dibujo-tecnico', 'bachillerato', '{2}', 'La perspectiva trimétrica usa tres coeficientes de reducción diferentes uno para cada eje del espacio tridimensional'),
('dibujo-tecnico', 'bachillerato', '{2}', 'La perspectiva dimétrica iguala dos de los tres coeficientes de reducción simplificando el trazado respecto a la trimétrica'),
('dibujo-tecnico', 'bachillerato', '{2}', 'El corte total muestra la sección completa del objeto como si se hubiera eliminado toda la parte delantera del mismo'),
('dibujo-tecnico', 'bachillerato', '{2}', 'El medio corte combina la mitad de la vista exterior con la mitad de la sección interior en piezas simétricas'),
('dibujo-tecnico', 'bachillerato', '{2}', 'El corte por planos paralelos se usa cuando un solo plano de corte no alcanza todos los detalles interiores del objeto'),
('dibujo-tecnico', 'bachillerato', '{2}', 'El rayado de las secciones se realiza con líneas finas inclinadas a cuarenta y cinco grados equidistantes entre sí'),
('dibujo-tecnico', 'bachillerato', '{2}', 'Las roscas se representan de forma simplificada mediante líneas continuas gruesas para la cresta y finas para el fondo'),
('dibujo-tecnico', 'bachillerato', '{2}', 'Las vistas auxiliares se utilizan para mostrar la verdadera forma de superficies inclinadas que aparecen deformadas en las vistas principales'),
('dibujo-tecnico', 'bachillerato', '{2}', 'La croquización es la representación a mano alzada de un objeto con todas sus dimensiones y detalles constructivos relevantes'),
('dibujo-tecnico', 'bachillerato', '{2}', 'El CAD permite crear dibujos técnicos por ordenador con precisión milimétrica y modificarlos fácilmente sin necesidad de redibujar'),
('dibujo-tecnico', 'bachillerato', '{2}', 'Los programas de modelado tridimensional generan sólidos virtuales a partir de operaciones de extrusión revolución y operaciones booleanas'),
('dibujo-tecnico', 'bachillerato', '{2}', 'El renderizado asigna materiales texturas e iluminación a un modelo tridimensional para obtener imágenes fotorrealistas del diseño'),
('dibujo-tecnico', 'bachillerato', '{2}', 'El BIM integra toda la información del proyecto constructivo en un modelo tridimensional inteligente accesible para todos los agentes'),
('dibujo-tecnico', 'bachillerato', '{2}', 'La impresión tridimensional permite fabricar prototipos físicos directamente a partir de los modelos digitales diseñados por ordenador'),
('dibujo-tecnico', 'bachillerato', '{2}', 'Las tolerancias dimensionales definen el rango de variación admisible en las medidas de una pieza fabricada industrialmente'),
('dibujo-tecnico', 'bachillerato', '{2}', 'El ajuste entre piezas puede ser con juego con apriete o indeterminado según la relación entre eje y agujero'),
('dibujo-tecnico', 'bachillerato', '{2}', 'Los acabados superficiales se indican en los planos técnicos mediante símbolos normalizados que especifican la rugosidad de la superficie'),
('dibujo-tecnico', 'bachillerato', '{2}', 'La acotación funcional sitúa las cotas según la función que desempeña cada dimensión en el montaje y uso de la pieza'),
('dibujo-tecnico', 'bachillerato', '{2}', 'El despiece es un plano que representa cada componente de un conjunto por separado con su acotación y su número de pieza'),
('dibujo-tecnico', 'bachillerato', '{2}', 'El plano de conjunto muestra todas las piezas ensambladas en su posición relativa dentro del mecanismo o dispositivo completo'),
('dibujo-tecnico', 'bachillerato', '{2}', 'La lista de materiales o nomenclador identifica cada pieza del conjunto con su número denominación material y cantidad necesaria'),
('dibujo-tecnico', 'bachillerato', '{2}', 'Las normas UNE son las normas españolas que unifican criterios de representación y acotación en el dibujo técnico industrial'),
('dibujo-tecnico', 'bachillerato', '{2}', 'Las normas ISO son estándares internacionales que aseguran la compatibilidad de los dibujos técnicos entre diferentes países y empresas'),
('dibujo-tecnico', 'bachillerato', '{2}', 'La sección abatida se representa girando el plano de corte hasta hacerlo coincidir con el plano del dibujo sin separar'),
('dibujo-tecnico', 'bachillerato', '{2}', 'El corte por planos concurrentes se emplea cuando la pieza tiene brazos o nervios dispuestos en ángulo desde un eje central'),
('dibujo-tecnico', 'bachillerato', '{2}', 'La representación de engranajes en planos técnicos utiliza convenciones simplificadas para indicar el diámetro primitivo y el número de dientes'),
('dibujo-tecnico', 'bachillerato', '{2}', 'Los chaveteros y ranuras se representan en los planos de taller con vistas auxiliares que muestran su forma y dimensiones exactas'),
('dibujo-tecnico', 'bachillerato', '{2}', 'La soldadura se indica en los planos mediante símbolos normalizados que especifican el tipo de unión y la posición del cordón'),
('dibujo-tecnico', 'bachillerato', '{2}', 'El dibujo de instalaciones eléctricas utiliza símbolos normalizados para representar interruptores enchufes y luminarias en los planos de planta'),
('dibujo-tecnico', 'bachillerato', '{2}', 'La perspectiva cónica se utiliza frecuentemente en arquitectura para mostrar al cliente el aspecto final del edificio proyectado'),
('dibujo-tecnico', 'bachillerato', '{2}', 'El diseño paramétrico permite modificar un modelo tridimensional cambiando sus dimensiones y el programa actualiza automáticamente toda la geometría'),
('dibujo-tecnico', 'bachillerato', '{2}', 'La geometría descriptiva es la disciplina que estudia la representación bidimensional de objetos tridimensionales mediante sistemas de proyección'),
('dibujo-tecnico', 'bachillerato', '{2}', 'La tercera proyección o vista lateral se obtiene proyectando el objeto sobre un plano de perfil perpendicular a los otros dos'),
('dibujo-tecnico', 'bachillerato', '{2}', 'El giro de un plano en diédrico permite obtener la verdadera magnitud de figuras contenidas en planos oblicuos al sistema'),
('dibujo-tecnico', 'bachillerato', '{2}', 'La recta de máxima pendiente de un plano es la de mayor inclinación respecto al plano horizontal de proyección'),
('dibujo-tecnico', 'bachillerato', '{2}', 'Las superficies regladas como el hiperboloide se generan mediante el movimiento continuo de una recta a lo largo de directrices'),
('dibujo-tecnico', 'bachillerato', '{2}', 'El paraboloide hiperbólico es una superficie alabeada que se utiliza en cubiertas arquitectónicas por su resistencia estructural y belleza'),
('dibujo-tecnico', 'bachillerato', '{2}', 'La intersección de un plano con un tetraedro produce un triángulo o un cuadrilátero según la posición relativa del corte'),
('dibujo-tecnico', 'bachillerato', '{2}', 'El método de las generatrices permite hallar la curva de intersección entre una superficie cónica y un plano secante cualquiera'),
('dibujo-tecnico', 'bachillerato', '{2}', 'La verdadera magnitud de la sección de un cilindro oblicuo se obtiene abatiendo el plano de corte sobre un plano de referencia'),
('dibujo-tecnico', 'bachillerato', '{2}', 'La perspectiva axonométrica oblicua proyecta los rayos de forma oblicua al plano del cuadro a diferencia de la ortogonal'),
('dibujo-tecnico', 'bachillerato', '{2}', 'Los planos tangentes a superficies curvas se determinan hallando las rectas tangentes a dos curvas de la superficie en un punto'),
('dibujo-tecnico', 'bachillerato', '{2}', 'La penetración de un prisma en un cilindro produce una curva de intersección que se determina punto a punto'),
('dibujo-tecnico', 'bachillerato', '{2}', 'El desarrollo de un cono oblicuo requiere triangular su superficie lateral para poder desplegarlo sobre un plano con precisión'),
('dibujo-tecnico', 'bachillerato', '{2}', 'El sistema acotado permite representar cubiertas y tejados indicando las pendientes y las líneas de cumbreras y limahoyas'),
('dibujo-tecnico', 'bachillerato', '{2}', 'La sección cónica de un toro puede ser una elipse una curva cerrada o dos circunferencias según el plano de corte'),
('dibujo-tecnico', 'bachillerato', '{2}', 'La fotogrametría utiliza fotografías para reconstruir modelos tridimensionales precisos de edificios y terrenos con técnicas de proyección'),
('dibujo-tecnico', 'bachillerato', '{2}', 'Las operaciones booleanas de unión intersección y diferencia permiten crear sólidos complejos a partir de formas primitivas simples'),
('dibujo-tecnico', 'bachillerato', '{2}', 'La realidad aumentada superpone modelos tridimensionales virtuales sobre el entorno real facilitando la visualización de proyectos arquitectónicos'),
('dibujo-tecnico', 'bachillerato', '{2}', 'El diseño generativo utiliza algoritmos y restricciones para que el ordenador proponga múltiples soluciones formales optimizadas automáticamente'),
('dibujo-tecnico', 'bachillerato', '{2}', 'La maqueta virtual permite recorrer un edificio tridimensional desde cualquier punto de vista antes de comenzar su construcción real'),
('dibujo-tecnico', 'bachillerato', '{2}', 'Las proyecciones cartográficas representan la superficie esférica de la Tierra sobre un plano generando inevitables deformaciones controladas'),
('dibujo-tecnico', 'bachillerato', '{2}', 'El análisis de elementos finitos simula el comportamiento estructural de piezas diseñadas por ordenador antes de su fabricación real'),
('dibujo-tecnico', 'bachillerato', '{2}', 'La fabricación asistida por ordenador traduce el modelo tridimensional en instrucciones para las máquinas herramienta de control numérico'),
('dibujo-tecnico', 'bachillerato', '{2}', 'El prototipado rápido permite validar el diseño de una pieza fabricando un modelo físico en pocas horas mediante impresión tridimensional'),
('dibujo-tecnico', 'bachillerato', '{2}', 'La ergonomía aplica criterios de diseño centrado en el usuario para que los productos se adapten a las necesidades humanas'),
('dibujo-tecnico', 'bachillerato', '{2}', 'La señalización industrial utiliza símbolos gráficos normalizados con colores y formas específicas para transmitir información de seguridad'),
('dibujo-tecnico', 'bachillerato', '{2}', 'El plano de urbanismo representa la distribución de parcelas calles zonas verdes y equipamientos de un sector de la ciudad'),
('dibujo-tecnico', 'bachillerato', '{2}', 'Los cortes parciales muestran únicamente una zona interior de la pieza delimitada por una línea de rotura irregular y fina'),
('dibujo-tecnico', 'bachillerato', '{2}', 'La sección transversal de un perfil metálico normalizado se representa indicando sus dimensiones y designación comercial en el plano'),
('dibujo-tecnico', 'bachillerato', '{2}', 'El escáner tridimensional captura la geometría de un objeto real y genera una nube de puntos que se convierte en modelo digital');
INSERT INTO ordena_frases (subject_id, level, grades, sentence) VALUES
('programacion', 'bachillerato', '{1}', 'La complejidad algorítmica mide la cantidad de recursos de tiempo y memoria que necesita un algoritmo en función del tamaño de entrada'),
('programacion', 'bachillerato', '{1}', 'La notación O grande describe el peor caso de crecimiento del tiempo de ejecución de un algoritmo cuando la entrada aumenta'),
('programacion', 'bachillerato', '{1}', 'Un algoritmo de búsqueda binaria divide repetidamente el espacio de búsqueda por la mitad consiguiendo una complejidad logarítmica'),
('programacion', 'bachillerato', '{1}', 'La búsqueda lineal recorre todos los elementos de una lista uno a uno hasta encontrar el valor buscado o llegar al final'),
('programacion', 'bachillerato', '{1}', 'El algoritmo de ordenación por burbuja compara pares adyacentes e intercambia los elementos desordenados en cada pasada por la lista'),
('programacion', 'bachillerato', '{1}', 'El quicksort selecciona un pivote y divide la lista en elementos menores y mayores que él para ordenarlos recursivamente'),
('programacion', 'bachillerato', '{1}', 'El mergesort divide la lista en mitades las ordena recursivamente y luego las fusiona en una lista ordenada final'),
('programacion', 'bachillerato', '{1}', 'Las listas enlazadas almacenan cada elemento junto con un puntero al siguiente nodo permitiendo inserciones y borrados eficientes'),
('programacion', 'bachillerato', '{1}', 'Una cola sigue el principio primero en entrar primero en salir conocido como FIFO para gestionar elementos en espera'),
('programacion', 'bachillerato', '{1}', 'Los árboles binarios de búsqueda organizan los datos de modo que cada nodo tiene valores menores a la izquierda y mayores a la derecha'),
('programacion', 'bachillerato', '{1}', 'Un grafo es una estructura de datos formada por vértices conectados por aristas que puede representar redes y relaciones'),
('programacion', 'bachillerato', '{1}', 'Las tablas hash permiten acceder a datos en tiempo constante promedio utilizando una función que calcula la posición del elemento'),
('programacion', 'bachillerato', '{1}', 'La encapsulación en programación orientada a objetos oculta los detalles internos de una clase exponiendo solo una interfaz pública'),
('programacion', 'bachillerato', '{1}', 'La abstracción permite modelar objetos del mundo real representando solo las características esenciales relevantes para el problema'),
('programacion', 'bachillerato', '{1}', 'Un constructor es un método especial que se ejecuta automáticamente al crear una nueva instancia de una clase en memoria'),
('programacion', 'bachillerato', '{1}', 'Los métodos getter y setter controlan el acceso a los atributos privados de una clase validando los valores asignados'),
('programacion', 'bachillerato', '{1}', 'La sobrecarga de métodos permite definir varias versiones del mismo método con diferente número o tipo de parámetros'),
('programacion', 'bachillerato', '{1}', 'Una interfaz define un contrato de métodos que las clases deben implementar sin especificar el código de cada uno'),
('programacion', 'bachillerato', '{1}', 'Las clases abstractas no se pueden instanciar directamente y sirven como base para otras clases que heredan su estructura'),
('programacion', 'bachillerato', '{1}', 'La composición establece una relación donde un objeto contiene a otros como parte de su estructura interna formando un todo'),
('programacion', 'bachillerato', '{1}', 'El modelo relacional organiza los datos en tablas donde cada fila es un registro y cada columna es un campo'),
('programacion', 'bachillerato', '{1}', 'La clave primaria identifica de forma única cada registro de una tabla y no puede contener valores nulos ni repetidos'),
('programacion', 'bachillerato', '{1}', 'La clave foránea establece una relación entre dos tablas referenciando la clave primaria de otra tabla de la base de datos'),
